% Datei einlesen (CSV mit 3 Spalten: x, y, z)
data = readmatrix('deltarobot_curve3.csv');

data(data(:,1) > 2500 | data(:,2) > 2500 | data(:,3) > 2500, :) = [];
% data(2:2:end, :) = [];

v = [3000 3000 3000];
% Abstand zur Geraden
dist = vecnorm(cross(data, repmat(v,size(data,1),1), 2), 2, 2) / norm(v);
% Projektion auf die Geradenrichtung
t = dot(data, repmat(v,size(data,1),1), 2) / dot(v,v) * 3000;
% Punkte im Bereich der beiden Ebenen
betweenPlanes = (t >= 1000) & (t <= 1900);
% löschen nur wenn beide Bedingungen erfüllt sind
data(dist < 250 & betweenPlanes, :) = [];

% Spalten extrahieren
x = data(:,1);
y = data(:,2);
z = data(:,3);

%------- ALPHASHAPE ------
% AlphaShape mit Alpha = 10 erzeugen
shp = alphaShape(x,y,z); %[output:9829f4d7]
alpha_crit = criticalAlpha(shp, 'one-region') * 1.5 %[output:86f8b560]
shp.Alpha = alpha_crit; %[output:229f1f07]

% Neue Figur
figure %[output:8804ef8a]

% Punktwolke darstellen
scatter3(x,y,z,5,'filled') %[output:8804ef8a]
hold on %[output:8804ef8a]

% AlphaShape darstellen
plot(shp,'FaceAlpha',0.3) %[output:8804ef8a]


% Achsenbeschriftung
xlabel('x') %[output:8804ef8a]
ylabel('y') %[output:8804ef8a]
zlabel('z') %[output:8804ef8a]

% Darstellung verbessern
axis equal %[output:8804ef8a]
grid on %[output:8804ef8a]
title('Alpha Shape der Punktwolke') %[output:8804ef8a]

plot3([0 2100], [0 2100], [0 2100], 'r-', 'LineWidth', 2) %[output:8804ef8a]

scatter3(723, 752, 749, 'r', 'filled') %[output:8804ef8a]

view(3) %[output:8804ef8a]
%%
% erste Rotationsmatrix berechnen
vektorRichtung = [3000 3000 3000] % equal to [1 1 1] %[output:15a3353b]
vektorRichtung = vektorRichtung / norm(vektorRichtung) % norm() returns length of vektorRichtung %[output:61bb1e24]

% vektorZiel is new z axis
vektorZiel = [0 0 1] %[output:754aa786]

vektorRotation = cross(vektorRichtung, vektorZiel) %[output:1c63c283]

skalarRichtungZiel = dot(vektorRichtung, vektorZiel) %[output:15c16d9e]
s = norm(vektorRotation) %[output:904e076e]

matrixRotation = [ 0                  -vektorRotation(3) vektorRotation(2); %[output:group:8d4d46ea] %[output:6b29a21c]
                   vektorRotation(3)  0                  -vektorRotation(1); %[output:6b29a21c]
                   -vektorRotation(2) vektorRotation(1)  0] %[output:group:8d4d46ea] %[output:6b29a21c]

matrixRotation = eye(3) + matrixRotation + matrixRotation*matrixRotation*((1 - skalarRichtungZiel)/(s^2)) %[output:03aa5e05]
%%
% erste Rotation vornehmen und Verschiebung
shp_Points_rot = (matrixRotation * shp.Points')' %[output:765501ed]
zMax = max(shp_Points_rot(:,3)) %[output:7653b936]
shp_Points_rot = [shp_Points_rot(:,1), shp_Points_rot(:,2), -shp_Points_rot(:,3) + zMax] %[output:80dda7d7]
%%
% zweite Rotationsmatrix um die z-Achse berechnen: passende Ausrichtung
vektorRichtung = [880 -210 0] %[output:2dbeea94]
vektorRichtung = vektorRichtung / norm(vektorRichtung) %[output:9f574b8f]

vektorZiel = [1 0 0] %[output:3f5228ae]

vektorRotation = cross(vektorRichtung, vektorZiel) %[output:463c664d]

skalarRichtungZiel = dot(vektorRichtung, vektorZiel);
s = norm(vektorRotation);

matrixRotation2 = [ 0                  -vektorRotation(3) vektorRotation(2); %[output:group:13aa70e6] %[output:2be718f8]
                   vektorRotation(3)  0                  -vektorRotation(1); %[output:2be718f8]
                   -vektorRotation(2) vektorRotation(1)  0] %[output:group:13aa70e6] %[output:2be718f8]

matrixRotation2 = eye(3) + matrixRotation2 + matrixRotation2*matrixRotation2*((1 - skalarRichtungZiel)/(s^2)) %[output:1be25fa5]
%%
% zweite Rotation vornehmen
shp_Points_rot2 = (matrixRotation2 * shp_Points_rot')' %[output:4ef65efd]
%%
% plotten
figure(2) %[output:8bf583a4]

scatter3(shp_Points_rot2(:,1), shp_Points_rot2(:,2), shp_Points_rot2(:,3)) %[output:8bf583a4]
hold on %[output:8bf583a4]
plot3([0 0], [0 0], [0 2100], 'r-', 'LineWidth', 2) %[output:8bf583a4]

xlabel('x') %[output:8bf583a4]
ylabel('y') %[output:8bf583a4]
zlabel('z') %[output:8bf583a4]
%%
% Point2PointTrans takes any given "point" in motor angle perspective as in
% [xmotor ymotor zmotor] and returns "point_transformed" which is the motor
% angle transformed into xyz coordinate sytem
function point_transformed = Point2PointTrans(point)
    vectorDirection = [1 1 1];
    zMax = 3.5241e+03;
    %zMax = max(shp_Points_rot(:,3)); 
    rotation_matrix1 = GetRotationMatrix1(vectorDirection);
    point_transformed = (rotation_matrix1 * point')';
    point_transformed = [point_transformed(1), point_transformed(2), -point_transformed(3)+zMax];
    
    % vectorAngleAdjustment rotates the point around the z axis by its
    % direction and length
    vectorAngleAdjustment = [880 -210 0];
    rotation_matrix2 = GetRotationMatrix2(vectorAngleAdjustment);
    point_transformed = (rotation_matrix2 * point_transformed')';
end

example_point = [2000 2000 2000];
point_transformed = Point2PointTrans(example_point) %[output:63a90a91]
%%
% Teil 1
function matrixRotation1 = GetRotationMatrix1(vectorDirection)
    normed_vectorDirection = vectorDirection / norm(vectorDirection);
    vectorZAxis = [0 0 1];
    vectorRotation = cross(normed_vectorDirection, vectorZAxis);
    normed_vectorRotation = norm(vectorRotation);

    scalarDirectionGoal = dot(normed_vectorDirection, vectorZAxis);
    
    matrixRotation1 = [0                   -vectorRotation(3) vectorRotation(2);
                     vectorRotation(3)    0                  -vectorRotation(1);
                     -vectorRotation(2)   vectorRotation(1)  0];

    matrixRotation1 = eye(3) + matrixRotation1 + matrixRotation1*matrixRotation1*((1 - scalarDirectionGoal)/(normed_vectorRotation^2));
end

% Teil 2
function matrixRotation2 = GetRotationMatrix2(vectorAngleAdjustment)
    normed_vectorAngleAdjustment = vectorAngleAdjustment / norm(vectorAngleAdjustment);
    vectorXAxis = [1 0 0];
    
    vectorRotation = cross(normed_vectorAngleAdjustment, vectorXAxis);
    normed_vectorRotation = norm(vectorRotation);
    
    scalarDirectionGoal = dot(normed_vectorAngleAdjustment, vectorXAxis);
    
    matrixRotation2 = [ 0                  -vectorRotation(3) vectorRotation(2);
                       vectorRotation(3)  0                  -vectorRotation(1);
                       -vectorRotation(2) vectorRotation(1)  0];
    
    matrixRotation2 = eye(3) + matrixRotation2 + matrixRotation2*matrixRotation2*((1 - scalarDirectionGoal)/(normed_vectorRotation^2));
end
%%
% Rücktransformation vornehmen
%point_trans = [-21.57 2.72 2239.54];
point_trans = [0 0 59.998384862245075];

point = PointTrans2Point(point_trans) %[output:401d1ae1]

% Reverse transformation
function point = PointTrans2Point(point_trans)
    vectorDirection = [1 1 1];
    % Müssen wir die Matrizen hier nochmal berechnen?
    matrixRotation1 = GetRotationMatrix1(vectorDirection);
    
    vectorAngleAdjustment = [880 -210 0];
    matrixRotation2 = GetRotationMatrix2(vectorAngleAdjustment);

    pointBeforeRot2 = (matrixRotation2' * point_trans')';
    pointBeforeRot2(3) = -(pointBeforeRot2(3) - 3524.1);
    pointBeforeRot1 = (matrixRotation1' * pointBeforeRot2')';
    point = pointBeforeRot1;
end


